public void Clicked()
{

    // int ret;
    FormDatasource     ProdTable_Ds;
    ProdParmReportFinished        prodParmReportFinished;
    boolean         orderType;
    FormControl     control = this;


    next Clicked();


    prodParmReportFinished  = control.formRun().dataSource(formDataSourceStr(ProdParmReportFinished,ProdParmReportFinished )).cursor();

    orderType = prodParmReportFinished.ETGProductionShift == ETGProductionShifts::None ? true : false;

    // ProdTable_Ds.object(fieldNum(ProdTable,BOMId)).mandatory(true);

    if(orderType)
    {
        throw Error(strFmt("ProductionShift must be filled in"));
    }

    // return ret;

}
